     1→/**
     2→ * MMS Infinite Canvas
     3→ *
     4→ * The main canvas component that renders PM schedule data at different zoom levels.
     5→ * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
     6→ *
     7→ * Zoom Level Rendering:
     8→ * - STRATEGIC (0-4): deck.gl WebGL heatmap
     9→ * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
    10→ * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
    11→ * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
    12→ * - DETAIL (16+): React DOM overlay
    13→ *
    14→ * Based on specs/006-user-interface.md Section 6.3.
    15→ */
    16→
    17→import { useRef } from 'react';
    18→import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup, OverlayToaster, Intent, Position } from '@blueprintjs/core';
    19→
    20→import { useCanvas, useCanvasData, useFleet, usePm, useUi, useOverlay, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData, loadBaselineShadowData } from '../../store';
    21→import type { CanvasSliceState } from '../../store/slices/canvas';
    22→import type { CanvasDataState } from '../../store/slices/canvas';
    23→import type { FleetSliceState } from '../../store/slices/fleet';
    24→import type { PmSliceState } from '../../store/slices/pm';
    25→import type { UiSliceState } from '../../store/slices/ui';
    26→import type { OverlaySliceState } from '../../store/slices/overlay';
    27→import type { ZoomLevel } from '../../store/types';
    28→import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock, type DragValidationState, type PmMoveImpact } from './layers';
    29→import { DragConfirmationDialog } from './DragConfirmationDialog';
    30→import {
    31→  quickValidatePmMove,
    32→  createDebouncedValidation,
    33→  getPmMoveImpact,
    34→  commitPmMove,
    35→  createCanvasKeyboardHandler,
    36→  type KeyboardHandlerCallbacks,
    37→  // Accessibility utilities
    38→  initializeAnnouncer,
    39→  announceZoomChange,
    40→  announcePmDeselection,
    41→  prefersReducedMotion,
    42→  onReducedMotionChange,
    43→  FOCUS_RING_STYLES,
    44→} from './utils';
    45→import { KeyboardShortcutsDialog } from '../KeyboardShortcutsDialog';
    46→import { Minimap } from './Minimap';
    47→
    48→// Toaster helper for showing notifications
    49→// Uses the static show method which handles async creation
    50→async function showToast(options: {
    51→  intent: typeof Intent[keyof typeof Intent];
    52→  icon: 'error' | 'tick' | 'warning-sign' | 'info-sign';
    53→  message: string;
    54→  timeout: number;
    55→}): Promise<void> {
    56→  const toaster = await OverlayToaster.createAsync({ position: Position.TOP_RIGHT });
    57→  toaster.show(options);
    58→}
    59→
    60→/** Default canvas dimensions when container size is not available */
    61→const DEFAULT_CANVAS_WIDTH = 1200;
    62→const DEFAULT_CANVAS_HEIGHT = 800;
    63→
    64→// Drag confirmation state interface
    65→interface DragConfirmState {
    66→  isOpen: boolean;
    67→  pmId: string | null;
    68→  pmCode: string;
    69→  trainNumber: string;
    70→  sourceDate: string;
    71→  targetDate: string;
    72→  impact: PmMoveImpact | null;
    73→  isLoadingImpact: boolean;
    74→}
    75→
    76→const initialDragConfirmState: DragConfirmState = {
    77→  isOpen: false,
    78→  pmId: null,
    79→  pmCode: '',
    80→  trainNumber: '',
    81→  sourceDate: '',
    82→  targetDate: '',
    83→  impact: null,
    84→  isLoadingImpact: false,
    85→};
    86→
    87→export function InfiniteCanvas() {
    88→  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
    89→  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
    90→  const { state: fleetStateRaw } = useFleet();
    91→  const { state: pmStateRaw, actions: pmActions } = usePm();
    92→  const { state: uiStateRaw, actions: uiActions } = useUi();
    93→  const { state: overlayStateRaw, actions: overlayActions } = useOverlay();
    94→
    95→  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
    96→  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
    97→  const fleetState = fleetStateRaw as unknown as FleetSliceState;
    98→  const pmState = pmStateRaw as unknown as PmSliceState;
    99→  const uiState = uiStateRaw as unknown as UiSliceState;
   100→  const overlayState = overlayStateRaw as unknown as OverlaySliceState;
   101→
   102→  const { zoom, zoomLevel, viewport, isPanning, layers } = canvasState;
   103→  const {
   104→    strategicData, strategicLoading, strategicError, fromYear, toYear,
   105→    tacticalWideData, tacticalWideLoading, tacticalWideError, tacticalWideFromDate, tacticalWideToDate,
   106→    tacticalData, tacticalLoading, tacticalError, tacticalFromDate, tacticalToDate,
   107→    operationalData, operationalLoading, operationalError, operationalFromDate, operationalToDate,
   108→    detailData, detailLoading, detailError, detailFromDate, detailToDate, detailExpandedPmIds
   109→  } = canvasDataState;
   110→  const isLoading = fleetState.trains.length === 0;
   111→
   112→  const tooltipPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
   113→  const tooltipRef = useRef<HTMLDivElement>(null);
   114→
   115→  // Drag state refs
   116→  const dragValidationRef = useRef<DragValidationState | null>(null);
   117→  const draggingPmRef = useRef<{
   118→    pmId: string;
   119→    pmCode: string;
   120→    trainId: string;
   121→    trainNumber: string;
