     1→/**
     2→ * Tactical Gantt Layer
     3→ *
     4→ * Konva-based Gantt chart layer for tactical PM scheduling (zoom levels 8-12).
     5→ * Renders PM blocks, constraint walls, train labels, and timeline axis.
     6→ *
     7→ * Features:
     8→ * - PM blocks with status-based colors
     9→ * - Compliance window constraint walls
    10→ * - Train labels on the left
    11→ * - Week/day timeline axis at top
    12→ * - Drag-and-drop PM rescheduling (with constraint validation)
    13→ * - Hover tooltips
    14→ *
    15→ * @see specs/006-user-interface.md Section 6.3.3
    16→ */
    17→
    18→import { useRef } from 'react';
    19→import { Stage, Layer, Rect, Text, Line, Group } from 'react-konva';
    20→import type { KonvaEventObject } from 'konva/lib/Node';
    21→import type { Stage as StageType } from 'konva/lib/Stage';
    22→
    23→import type { PmBlock, ConstraintWall, TacticalCanvasData, DragValidationState, BaselineShadowData } from './types';
    24→import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';
    25→
    26→/** Baseline shadow block colors by status */
    27→const BASELINE_SHADOW_COLORS = {
    28→  UNCHANGED: 'rgba(156, 163, 175, 0.2)', // Gray, nearly invisible
    29→  MOVED: 'rgba(234, 179, 8, 0.3)', // Yellow/amber for moved
    30→  ADDED: 'rgba(34, 197, 94, 0.3)', // Green for added
    31→  REMOVED: 'rgba(239, 68, 68, 0.3)', // Red for removed
    32→};
    33→
    34→// =============================================================================
    35→// Constants
    36→// =============================================================================
    37→
    38→/** Layout constants for the Gantt chart */
    39→const LAYOUT = {
    40→  HEADER_HEIGHT: 48,
    41→  TRAIN_LABEL_WIDTH: 120,
    42→  ROW_HEIGHT: 40,
    43→  PM_BLOCK_HEIGHT: 28,
    44→  PM_BLOCK_MARGIN: 6,
    45→  DAY_WIDTH: 24,
    46→  WEEK_WIDTH: 24 * 7,
    47→  MIN_PM_WIDTH: 20,
    48→  CONSTRAINT_WALL_WIDTH: 2,
    49→  GRID_LINE_COLOR: '#e2e8f0',
    50→  HEADER_BG: '#f8fafc',
    51→  TRAIN_LABEL_BG: '#ffffff',
    52→  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
    53→};
    54→
    55→/** PM status to color mapping */
    56→function getPmColor(status: string): string {
    57→  switch (status) {
    58→    case 'SCHEDULED':
    59→      return PM_STATUS_COLORS.scheduled;
    60→    case 'IN_PROGRESS':
    61→      return PM_STATUS_COLORS.inProgress;
    62→    case 'COMPLETED':
    63→      return PM_STATUS_COLORS.completed;
    64→    case 'CANCELLED':
    65→      return PM_STATUS_COLORS.cancelled;
    66→    case 'DEFERRED':
    67→      return PM_STATUS_COLORS.deferred;
    68→    default:
    69→      return PM_STATUS_COLORS.scheduled;
    70→  }
    71→}
    72→
    73→// =============================================================================
    74→// Types
    75→// =============================================================================
    76→
    77→export interface TacticalGanttLayerProps {
    78→  data: TacticalCanvasData | null;
    79→  trainOrder: string[];
    80→  fromDate: Date;
    81→  toDate: Date;
    82→  width: number;
    83→  height: number;
    84→  selectedPmIds: string[];
    85→  /** ID of the PM currently being dragged (if any) */
    86→  draggingPmId?: string | null;
    87→  /** Validation state for the current drag operation */
    88→  dragValidation?: DragValidationState | null;
    89→  /** Baseline shadow data for showing PM positions from baseline */
    90→  baselineShadowData?: BaselineShadowData | null;
    91→  onPmClick?: (pmId: string) => void;
    92→  onPmHover?: (pm: PmBlock | null) => void;
    93→  /** Called when drag starts - includes source date */
    94→  onPmDragStart?: (pmId: string, sourceDate: string) => void;
    95→  /** Called during drag as position changes - for real-time validation */
    96→  onPmDragMove?: (pmId: string, targetDate: string) => void;
    97→  /** Called when drag ends - for final commit/cancel */
    98→  onPmDragEnd?: (pmId: string, newDate: string) => void;
    99→  showConstraintWalls?: boolean;
   100→  showGrid?: boolean;
   101→}
   102→
   103→interface DayData {
   104→  date: Date;
   105→  dateStr: string;
   106→  dayOfWeek: number;
   107→  isWeekStart: boolean;
   108→  isToday: boolean;
   109→}
   110→
   111→interface WeekData {
   112→  weekStart: Date;
   113→  weekNum: number;
   114→  daysInWeek: number;
   115→}
   116→
   117→// =============================================================================
   118→// Pure Utility Functions
   119→// =============================================================================
   120→
   121→function getDays(fromDate: Date, toDate: Date): DayData[] {
   122→  const days: DayData[] = [];
   123→  const current = new Date(fromDate);
   124→  const today = new Date();
   125→  today.setHours(0, 0, 0, 0);
   126→
   127→  while (current <= toDate) {
   128→    const dayOfWeek = current.getDay();
   129→    days.push({
   130→      date: new Date(current),
   131→      dateStr: current.toISOString().split('T')[0],
   132→      dayOfWeek,
   133→      isWeekStart: dayOfWeek === 0,
   134→      isToday: current.getTime() === today.getTime(),
   135→    });
   136→    current.setDate(current.getDate() + 1);
   137→  }
   138→  return days;
   139→}
   140→
   141→function getWeeks(days: DayData[]): WeekData[] {
   142→  const weeks: WeekData[] = [];
   143→  let currentWeek: WeekData | null = null;
   144→
   145→  for (const day of days) {
   146→    if (day.isWeekStart || currentWeek === null) {
   147→      if (currentWeek) {
   148→        weeks.push(currentWeek);
   149→      }
   150→      const weekNum = getWeekNumber(day.date);
   151→      currentWeek = { weekStart: day.date, weekNum, daysInWeek: 1 };
   152→    } else {
   153→      currentWeek.daysInWeek++;
   154→    }
   155→  }
   156→  if (currentWeek) {
   157→    weeks.push(currentWeek);
   158→  }
   159→  return weeks;
   160→}
   161→
   162→function getWeekNumber(date: Date): number {
   163→  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
   164→  const dayNum = d.getUTCDay() || 7;
   165→  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
   166→  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
   167→  return Math.ceil(((d.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);
   168→}
   169→
   170→function dateDiffDays(a: Date, b: Date): number {
   171→  return Math.floor((a.getTime() - b.getTime()) / (1000 * 60 * 60 * 24));
   172→}
   173→
   174→function parseDate(dateStr: string): Date {
   175→  return new Date(dateStr + 'T00:00:00');
   176→}
   177→
   178→function buildTrainIndexMap(trainOrder: string[]): Map<string, number> {
   179→  const map = new Map<string, number>();
   180→  trainOrder.forEach((id, i) => map.set(id, i));
   181→  return map;
   182→}
   183→
   184→function buildTrainMetadata(pmBlocks: PmBlock[]): { numbers: Map<string, string>; fleets: Map<string, string> } {
   185→  const numbers = new Map<string, string>();
   186→  const fleets = new Map<string, string>();
   187→
   188→  for (const pm of pmBlocks) {
   189→    if (!numbers.has(pm.trainId)) {
   190→      numbers.set(pm.trainId, pm.trainNumber);
   191→      const code = pm.trainNumber.split('-')[0] || 'KS';
   192→      fleets.set(pm.trainId, code);
   193→    }
   194→  }
   195→
   196→  return { numbers, fleets };
   197→}
   198→
   199→// =============================================================================
   200→// Sub-Components
   201→// =============================================================================
   202→
   203→interface TimelineHeaderProps {
   204→  days: DayData[];
   205→  weeks: WeekData[];
   206→  offsetX: number;
   207→}
   208→
   209→function TimelineHeader({ days, weeks, offsetX }: TimelineHeaderProps) {
   210→  return (
   211→    <Group x={offsetX} y={0}>
   212→      {/* Week row */}
   213→      <Rect
   214→        x={0}
   215→        y={0}
   216→        width={days.length * LAYOUT.DAY_WIDTH}
   217→        height={LAYOUT.HEADER_HEIGHT / 2}
   218→        fill={LAYOUT.HEADER_BG}
   219→      />
   220→      {weeks.map((week, i) => {
   221→        const x = days.findIndex((d) => d.date.getTime() === week.weekStart.getTime()) * LAYOUT.DAY_WIDTH;
   222→        const width = week.daysInWeek * LAYOUT.DAY_WIDTH;
   223→        return (
   224→          <Group key={i} x={x} y={0}>
   225→            <Rect
   226→              width={width}
   227→              height={LAYOUT.HEADER_HEIGHT / 2}
   228→              stroke={LAYOUT.GRID_LINE_COLOR}
   229→              strokeWidth={1}
   230→            />
   231→            <Text
   232→              x={4}
   233→              y={6}
   234→              text={`Week ${week.weekNum}`}
   235→              fontSize={11}
   236→              fontFamily={LAYOUT.FONT_FAMILY}
   237→              fill="#64748b"
   238→            />
   239→          </Group>
   240→        );
   241→      })}
   242→
   243→      {/* Day row */}
   244→      {days.map((day, i) => (
   245→        <Group key={day.dateStr} x={i * LAYOUT.DAY_WIDTH} y={LAYOUT.HEADER_HEIGHT / 2}>
   246→          <Rect
   247→            width={LAYOUT.DAY_WIDTH}
   248→            height={LAYOUT.HEADER_HEIGHT / 2}
   249→            fill={day.isToday ? '#dbeafe' : day.dayOfWeek === 0 || day.dayOfWeek === 6 ? '#f1f5f9' : LAYOUT.HEADER_BG}
   250→            stroke={LAYOUT.GRID_LINE_COLOR}
   251→            strokeWidth={0.5}
   252→          />
   253→          <Text
   254→            x={2}
   255→            y={6}
   256→            text={['S', 'M', 'T', 'W', 'T', 'F', 'S'][day.dayOfWeek]}
   257→            fontSize={9}
   258→            fontFamily={LAYOUT.FONT_FAMILY}
   259→            fill={day.isToday ? '#2563eb' : '#94a3b8'}
   260→          />
   261→          <Text
   262→            x={2}
   263→            y={15}
   264→            text={String(day.date.getDate())}
   265→            fontSize={9}
   266→            fontFamily={LAYOUT.FONT_FAMILY}
   267→            fill={day.isToday ? '#2563eb' : '#64748b'}
   268→            fontStyle={day.isToday ? 'bold' : 'normal'}
   269→          />
   270→        </Group>
   271→      ))}
   272→    </Group>
   273→  );
   274→}
   275→
   276→interface TrainLabelsPanelProps {
   277→  trainOrder: string[];
   278→  trainNumbers: Map<string, string>;
   279→  fleetCodes: Map<string, string>;
   280→}
   281→
   282→function TrainLabelsPanel({ trainOrder, trainNumbers, fleetCodes }: TrainLabelsPanelProps) {
   283→  return (
   284→    <Group x={0} y={LAYOUT.HEADER_HEIGHT}>
   285→      <Rect
   286→        width={LAYOUT.TRAIN_LABEL_WIDTH}
   287→        height={trainOrder.length * LAYOUT.ROW_HEIGHT}
   288→        fill={LAYOUT.TRAIN_LABEL_BG}
   289→      />
   290→      {trainOrder.map((trainId, i) => {
   291→        const trainNumber = trainNumbers.get(trainId) || trainId.slice(0, 8);
   292→        const fleetCode = fleetCodes.get(trainId) || 'KS';
   293→        const fleetColor = FLEET_COLORS[fleetCode as keyof typeof FLEET_COLORS] || FLEET_COLORS.KS;
   294→
   295→        return (
   296→          <Group key={trainId} y={i * LAYOUT.ROW_HEIGHT}>
   297→            <Rect
   298→              width={LAYOUT.TRAIN_LABEL_WIDTH}
   299→              height={LAYOUT.ROW_HEIGHT}
   300→              stroke={LAYOUT.GRID_LINE_COLOR}
   301→              strokeWidth={0.5}
   302→            />
   303→            <Rect
   304→              x={4}
   305→              y={10}
   306→              width={4}
   307→              height={LAYOUT.ROW_HEIGHT - 20}
   308→              fill={fleetColor}
   309→              cornerRadius={2}
   310→            />
   311→            <Text
   312→              x={14}
   313→              y={12}
   314→              text={trainNumber}
   315→              fontSize={12}
   316→              fontFamily={LAYOUT.FONT_FAMILY}
   317→              fill="#1e293b"
   318→              fontStyle="bold"
   319→            />
   320→            <Text
   321→              x={14}
   322→              y={26}
   323→              text={fleetCode}
   324→              fontSize={10}
   325→              fontFamily={LAYOUT.FONT_FAMILY}
   326→              fill="#64748b"
   327→            />
   328→          </Group>
   329→        );
   330→      })}
   331→    </Group>
   332→  );
   333→}
   334→
   335→interface GanttGridProps {
   336→  days: DayData[];
   337→  rowCount: number;
   338→  offsetX: number;
   339→}
   340→
   341→function GanttGrid({ days, rowCount, offsetX }: GanttGridProps) {
   342→  const weekStartDays = days.filter((d) => d.isWeekStart);
   343→  const todayIndex = days.findIndex((d) => d.isToday);
   344→
   345→  return (
   346→    <Group x={offsetX} y={LAYOUT.HEADER_HEIGHT}>
   347→      {/* Row backgrounds */}
   348→      {Array.from({ length: rowCount }).map((_, i) => (
   349→        <Rect
   350→          key={i}
   351→          y={i * LAYOUT.ROW_HEIGHT}
   352→          width={days.length * LAYOUT.DAY_WIDTH}
   353→          height={LAYOUT.ROW_HEIGHT}
   354→          fill={i % 2 === 0 ? '#ffffff' : '#fafafa'}
   355→          stroke={LAYOUT.GRID_LINE_COLOR}
   356→          strokeWidth={0.5}
   357→        />
   358→      ))}
   359→
   360→      {/* Day columns - today highlight */}
   361→      {todayIndex >= 0 && (
   362→        <Rect
   363→          x={todayIndex * LAYOUT.DAY_WIDTH}
   364→          y={0}
   365→          width={LAYOUT.DAY_WIDTH}
   366→          height={rowCount * LAYOUT.ROW_HEIGHT}
   367→          fill="rgba(37, 99, 235, 0.05)"
   368→        />
   369→      )}
   370→
   371→      {/* Week separators */}
   372→      {weekStartDays.map((day) => {
   373→        const x = days.indexOf(day) * LAYOUT.DAY_WIDTH;
   374→        return (
   375→          <Line
   376→            key={`week-${day.dateStr}`}
   377→            points={[x, 0, x, rowCount * LAYOUT.ROW_HEIGHT]}
   378→            stroke="#cbd5e1"
   379→            strokeWidth={1}
   380→          />
   381→        );
   382→      })}
   383→
   384→      {/* Today line */}
   385→      {todayIndex >= 0 && (
   386→        <Line
   387→          points={[
   388→            todayIndex * LAYOUT.DAY_WIDTH,
   389→            0,
   390→            todayIndex * LAYOUT.DAY_WIDTH,
   391→            rowCount * LAYOUT.ROW_HEIGHT,
   392→          ]}
   393→          stroke="#2563eb"
   394→          strokeWidth={2}
   395→          dash={[4, 4]}
   396→        />
   397→      )}
   398→    </Group>
   399→  );
   400→}
   401→
   402→interface PmBlockRectProps {
   403→  pm: PmBlock;
   404→  x: number;
   405→  y: number;
   406→  width: number;
   407→  isSelected: boolean;
   408→  isDragging?: boolean;
   409→  dragValidation?: DragValidationState | null;
   410→  onHover?: (pm: PmBlock | null) => void;
   411→  onClick?: (pmId: string) => void;
   412→  onDragStart?: (pmId: string, sourceDate: string) => void;
   413→  onDragMove?: (pmId: string, targetDate: string) => void;
   414→  onDragEnd?: (pmId: string, newDate: string) => void;
   415→  fromDate: Date;
   416→}
   417→
   418→function PmBlockRect({
   419→  pm,
   420→  x,
   421→  y,
   422→  width,
   423→  isSelected,
   424→  isDragging,
   425→  dragValidation,
   426→  onHover,
   427→  onClick,
   428→  onDragStart,
   429→  onDragMove,
   430→  onDragEnd,
   431→  fromDate,
   432→}: PmBlockRectProps) {
   433→  const color = pm.displayColor || getPmColor(pm.status);
   434→  const finalWidth = Math.max(width, LAYOUT.MIN_PM_WIDTH);
   435→
   436→  const handleDragStart = () => {
   437→    if (onDragStart) {
   438→      onDragStart(pm.pmId, pm.targetDate);
   439→    }
   440→  };
   441→
   442→  const handleDragMove = (e: KonvaEventObject<DragEvent>) => {
   443→    if (onDragMove) {
   444→      const newX = e.target.x();
   445→      const dayOffset = Math.round(newX / LAYOUT.DAY_WIDTH);
   446→      const newDate = new Date(fromDate);
   447→      newDate.setDate(newDate.getDate() + dayOffset);
   448→      onDragMove(pm.pmId, newDate.toISOString().split('T')[0]);
   449→    }
   450→  };
   451→
   452→  const handleDragEnd = (e: KonvaEventObject<DragEvent>) => {
   453→    if (onDragEnd) {
   454→      const newX = e.target.x();
   455→      const dayOffset = Math.round(newX / LAYOUT.DAY_WIDTH);
   456→      const newDate = new Date(fromDate);
   457→      newDate.setDate(newDate.getDate() + dayOffset);
   458→      onDragEnd(pm.pmId, newDate.toISOString().split('T')[0]);
   459→    }
   460→  };
   461→
   462→  // Determine border color based on drag validation state
   463→  let borderColor = isSelected ? '#1d4ed8' : '#00000015';
   464→  let borderWidth = 1;
   465→  let shadowBlur = 2;
   466→
   467→  if (isDragging && dragValidation) {
   468→    if (dragValidation.isValid) {
   469→      // Valid drop - green outline
   470→      borderColor = '#22c55e'; // Green-500
   471→      borderWidth = 3;
   472→      shadowBlur = 8;
   473→    } else {
   474→      // Invalid drop - red outline
   475→      borderColor = '#ef4444'; // Red-500
   476→      borderWidth = 3;
   477→      shadowBlur = 8;
   478→    }
   479→  }
   480→
   481→  return (
   482→    <Group
   483→      x={x}
   484→      y={y}
   485→      draggable={!pm.isLocked}
   486→      onDragStart={handleDragStart}
   487→      onDragMove={handleDragMove}
   488→      onDragEnd={handleDragEnd}
   489→      onMouseEnter={() => onHover?.(pm)}
   490→      onMouseLeave={() => onHover?.(null)}
   491→      onClick={() => onClick?.(pm.pmId)}
   492→    >
   493→      {/* Shadow for selected or dragging */}
   494→      {(isSelected || isDragging) && (
   495→        <Rect
   496→          x={-3}
   497→          y={-3}
   498→          width={finalWidth + 6}
   499→          height={LAYOUT.PM_BLOCK_HEIGHT + 6}
   500→          fill="transparent"
   501→          stroke={isDragging && dragValidation
   502→            ? (dragValidation.isValid ? '#22c55e' : '#ef4444')
   503→            : '#3b82f6'
   504→          }
   505→          strokeWidth={isDragging ? 3 : 2}
   506→          cornerRadius={6}
   507→          dash={isDragging ? undefined : undefined}
   508→          opacity={isDragging ? 0.8 : 1}
   509→        />
   510→      )}
   511→
   512→      {/* Drag validation indicator glow */}
   513→      {isDragging && dragValidation && (
   514→        <Rect
   515→          x={-6}
   516→          y={-6}
   517→          width={finalWidth + 12}
   518→          height={LAYOUT.PM_BLOCK_HEIGHT + 12}
   519→          fill="transparent"
   520→          stroke={dragValidation.isValid ? 'rgba(34, 197, 94, 0.3)' : 'rgba(239, 68, 68, 0.3)'}
   521→          strokeWidth={8}
   522→          cornerRadius={10}
   523→        />
   524→      )}
   525→
   526→      {/* PM block */}
   527→      <Rect
   528→        width={finalWidth}
   529→        height={LAYOUT.PM_BLOCK_HEIGHT}
   530→        fill={color}
   531→        stroke={borderColor}
   532→        strokeWidth={borderWidth}
   533→        cornerRadius={4}
   534→        shadowColor={isDragging ? (dragValidation?.isValid ? '#22c55e' : '#ef4444') : '#000'}
   535→        shadowBlur={shadowBlur}
   536→        shadowOpacity={isDragging ? 0.4 : 0.1}
   537→        shadowOffsetY={isDragging ? 4 : 1}
   538→      />
   539→
   540→      {/* Lock indicator */}
   541→      {pm.isLocked && (
   542→        <Text
   543→          x={4}
   544→          y={7}
   545→          text="🔒"
   546→          fontSize={10}
   547→        />
   548→      )}
   549→
   550→      {/* PM code label */}
   551→      <Text
   552→        x={pm.isLocked ? 18 : 6}
   553→        y={7}
   554→        text={pm.pmCode}
   555→        fontSize={11}
   556→        fontFamily={LAYOUT.FONT_FAMILY}
   557→        fill="#ffffff"
   558→        fontStyle="bold"
   559→      />
   560→
   561→      {/* Duration label (if space) */}
   562→      {finalWidth > 50 && pm.estimatedHours && (
   563→        <Text
   564→          x={finalWidth - 30}
   565→          y={8}
   566→          text={`${pm.estimatedHours}h`}
   567→          fontSize={9}
   568→          fontFamily={LAYOUT.FONT_FAMILY}
   569→          fill="rgba(255,255,255,0.8)"
   570→        />
   571→      )}
   572→
   573→      {/* Drag validation status icon */}
   574→      {isDragging && dragValidation && (
   575→        <Group x={finalWidth - 16} y={-8}>
   576→          <Rect
   577→            width={20}
   578→            height={20}
   579→            fill={dragValidation.isValid ? '#22c55e' : '#ef4444'}
   580→            cornerRadius={10}
   581→            shadowColor="#000"
   582→            shadowBlur={4}
   583→            shadowOpacity={0.3}
   584→          />
   585→          <Text
   586→            x={4}
   587→            y={3}
   588→            text={dragValidation.isValid ? '✓' : '✗'}
   589→            fontSize={12}
   590→            fill="#ffffff"
   591→            fontStyle="bold"
   592→          />
   593→        </Group>
   594→      )}
   595→    </Group>
   596→  );
   597→}
   598→
   599→interface ConstraintWallsLayerProps {
   600→  walls: ConstraintWall[];
   601→  trainOrder: string[];
   602→  days: DayData[];
   603→  pmBlocks: PmBlock[];
   604→  offsetX: number;
   605→}
   606→
   607→function ConstraintWallsLayer({ walls, trainOrder, days, pmBlocks, offsetX }: ConstraintWallsLayerProps) {
   608→  const trainIndexMap = buildTrainIndexMap(trainOrder);
   609→  const pmBlockMap = new Map<string, PmBlock>();
   610→  pmBlocks.forEach((pm) => pmBlockMap.set(pm.pmId, pm));
   611→
   612→  return (
   613→    <Group x={offsetX} y={LAYOUT.HEADER_HEIGHT}>
   614→      {walls.map((wall) => {
   615→        const pm = pmBlockMap.get(wall.pmId);
   616→        if (!pm) return null;
   617→
   618→        const trainIndex = trainIndexMap.get(pm.trainId);
   619→        if (trainIndex === undefined) return null;
   620→
   621→        const dayIndex = days.findIndex((d) => d.dateStr === wall.date);
   622→        if (dayIndex < 0) return null;
   623→
   624→        const x = dayIndex * LAYOUT.DAY_WIDTH;
   625→        const y = trainIndex * LAYOUT.ROW_HEIGHT;
   626→        const color = wall.type === 'COMPLIANCE_START'
   627→          ? CONSTRAINT_COLORS.approaching
   628→          : CONSTRAINT_COLORS.hardViolation;
   629→
   630→        return (
   631→          <Line
   632→            key={`${wall.pmId}-${wall.type}`}
   633→            points={[x, y + 4, x, y + LAYOUT.ROW_HEIGHT - 4]}
   634→            stroke={color}
   635→            strokeWidth={LAYOUT.CONSTRAINT_WALL_WIDTH}
   636→            dash={[4, 2]}
   637→          />
   638→        );
   639→      })}
   640→    </Group>
   641→  );
   642→}
   643→
   644→// =============================================================================
   645→// Main Component
   646→// =============================================================================
   647→
   648→export function TacticalGanttLayer({
   649→  data,
   650→  trainOrder,
   651→  fromDate,
   652→  toDate,
   653→  width,
   654→  height,
   655→  selectedPmIds,
   656→  draggingPmId,
   657→  dragValidation,
   658→  baselineShadowData,
   659→  onPmClick,
   660→  onPmHover,
   661→  onPmDragStart,
   662→  onPmDragMove,
   663→  onPmDragEnd,
   664→  showConstraintWalls = true,
   665→  showGrid = true,
   666→}: TacticalGanttLayerProps) {
   667→  const stageRef = useRef<StageType>(null);
   668→
   669→  if (!data) {
   670→    return null;
   671→  }
   672→
   673→  // Compute derived data inline (no useMemo - pure functions)
   674→  const days = getDays(fromDate, toDate);
   675→  const weeks = getWeeks(days);
   676→  const trainIndexMap = buildTrainIndexMap(trainOrder);
   677→  const { numbers: trainNumbers, fleets: fleetCodes } = buildTrainMetadata(data.pmBlocks);
   678→  const selectedSet = new Set(selectedPmIds);
   679→
   680→  const gridOffsetX = LAYOUT.TRAIN_LABEL_WIDTH;
   681→  const contentWidth = days.length * LAYOUT.DAY_WIDTH + gridOffsetX;
   682→  const contentHeight = trainOrder.length * LAYOUT.ROW_HEIGHT + LAYOUT.HEADER_HEIGHT;
   683→
   684→  return (
   685→    <Stage
   686→      ref={stageRef}
   687→      width={width}
   688→      height={height}
   689→      style={{ backgroundColor: '#f8fafc' }}
   690→    >
   691→      {/* Background layer */}
   692→      <Layer>
   693→        <Rect width={contentWidth} height={contentHeight} fill="#ffffff" />
   694→      </Layer>
   695→
   696→      {/* Grid layer */}
   697→      {showGrid && (
   698→        <Layer>
   699→          <GanttGrid days={days} rowCount={trainOrder.length} offsetX={gridOffsetX} />
   700→        </Layer>
   701→      )}
   702→
   703→      {/* Constraint walls layer */}
   704→      {showConstraintWalls && data.constraintWalls.length > 0 && (
   705→        <Layer>
   706→          <ConstraintWallsLayer
   707→            walls={data.constraintWalls}
   708→            trainOrder={trainOrder}
   709→            days={days}
   710→            pmBlocks={data.pmBlocks}
   711→            offsetX={gridOffsetX}
   712→          />
   713→        </Layer>
   714→      )}
   715→
   716→      {/* Baseline shadow layer (shows PM positions from baseline) */}
   717→      {baselineShadowData && baselineShadowData.pmBlocks.length > 0 && (
   718→        <Layer>
   719→          <Group x={gridOffsetX} y={LAYOUT.HEADER_HEIGHT}>
   720→            {baselineShadowData.pmBlocks.map((bpm) => {
   721→              const trainIndex = trainIndexMap.get(bpm.trainId);
   722→              if (trainIndex === undefined) return null;
   723→
   724→              const baselineDate = parseDate(bpm.baselineDate);
   725→              const dayOffset = dateDiffDays(baselineDate, fromDate);
   726→              if (dayOffset < 0 || dayOffset >= days.length) return null;
   727→
   728→              const x = dayOffset * LAYOUT.DAY_WIDTH;
   729→              const y = trainIndex * LAYOUT.ROW_HEIGHT + LAYOUT.PM_BLOCK_MARGIN;
   730→              const blockWidth = LAYOUT.DAY_WIDTH * 2 - 4; // Default 2-day width for shadow
   731→
   732→              // Get color based on drift status
   733→              const shadowColor = BASELINE_SHADOW_COLORS[bpm.status] || BASELINE_SHADOW_COLORS.UNCHANGED;
   734→
   735→              // For MOVED PMs, draw a dashed outline where it was in baseline
   736→              if (bpm.status === 'MOVED' || bpm.status === 'REMOVED') {
   737→                return (
   738→                  <Group key={`baseline-${bpm.pmId}`}>
   739→                    {/* Shadow fill */}
   740→                    <Rect
   741→                      x={x}
   742→                      y={y}
   743→                      width={blockWidth}
   744→                      height={LAYOUT.PM_BLOCK_HEIGHT}
   745→                      fill={shadowColor}
   746→                      cornerRadius={4}
   747→                    />
   748→                    {/* Dashed border */}
   749→                    <Rect
   750→                      x={x}
   751→                      y={y}
   752→                      width={blockWidth}
   753→                      height={LAYOUT.PM_BLOCK_HEIGHT}
   754→                      stroke={bpm.status === 'REMOVED' ? '#EF4444' : '#F59E0B'}
   755→                      strokeWidth={1.5}
   756→                      dash={[4, 2]}
   757→                      cornerRadius={4}
   758→                    />
   759→                    {/* PM code label */}
   760→                    <Text
   761→                      x={x + 4}
   762→                      y={y + 6}
   763→                      text={bpm.pmCode}
   764→                      fontSize={10}
   765→                      fontFamily={LAYOUT.FONT_FAMILY}
   766→                      fill={bpm.status === 'REMOVED' ? '#DC2626' : '#D97706'}
   767→                      opacity={0.7}
   768→                    />
   769→                  </Group>
   770→                );
   771→              }
   772→
   773→              // For ADDED PMs (new in current schedule), show green indicator
   774→              if (bpm.status === 'ADDED') {
   775→                return (
   776→                  <Rect
   777→                    key={`baseline-${bpm.pmId}`}
   778→                    x={x - 2}
   779→                    y={y - 2}
   780→                    width={4}
   781→                    height={LAYOUT.PM_BLOCK_HEIGHT + 4}
   782→                    fill="#22C55E"
   783→                    cornerRadius={2}
   784→                    opacity={0.6}
   785→                  />
   786→                );
   787→              }
   788→
   789→              // UNCHANGED - very subtle indicator
   790→              return null;
   791→            })}
   792→          </Group>
   793→        </Layer>
   794→      )}
   795→
   796→      {/* PM blocks layer */}
   797→      <Layer>
   798→        <Group x={gridOffsetX} y={LAYOUT.HEADER_HEIGHT}>
   799→          {data.pmBlocks.map((pm) => {
   800→            const trainIndex = trainIndexMap.get(pm.trainId);
   801→            if (trainIndex === undefined) return null;
   802→
   803→            const pmDate = parseDate(pm.targetDate);
   804→            const dayOffset = dateDiffDays(pmDate, fromDate);
   805→            if (dayOffset < 0 || dayOffset >= days.length) return null;
   806→
   807→            const x = dayOffset * LAYOUT.DAY_WIDTH;
   808→            const y = trainIndex * LAYOUT.ROW_HEIGHT + LAYOUT.PM_BLOCK_MARGIN;
   809→            const blockWidth = pm.durationDays * LAYOUT.DAY_WIDTH - 4;
   810→
   811→            return (
   812→              <PmBlockRect
   813→                key={pm.pmId}
   814→                pm={pm}
   815→                x={x}
   816→                y={y}
   817→                width={blockWidth}
   818→                isSelected={selectedSet.has(pm.pmId)}
   819→                isDragging={draggingPmId === pm.pmId}
   820→                dragValidation={draggingPmId === pm.pmId ? dragValidation : null}
   821→                onHover={onPmHover}
   822→                onClick={onPmClick}
   823→                onDragStart={onPmDragStart}
   824→                onDragMove={onPmDragMove}
   825→                onDragEnd={onPmDragEnd}
   826→                fromDate={fromDate}
   827→              />
   828→            );
   829→          })}
   830→        </Group>
   831→      </Layer>
   832→
   833→      {/* Timeline header layer (on top) */}
   834→      <Layer>
   835→        <TimelineHeader days={days} weeks={weeks} offsetX={gridOffsetX} />
   836→      </Layer>
   837→
   838→      {/* Train labels layer (fixed left) */}
   839→      <Layer>
   840→        <TrainLabelsPanel
   841→          trainOrder={trainOrder}
   842→          trainNumbers={trainNumbers}
   843→          fleetCodes={fleetCodes}
   844→        />
   845→      </Layer>
   846→    </Stage>
   847→  );
   848→}
   849→
   850→export default TacticalGanttLayer;
   851→

