/**
 * Tactical Gantt Layer
 *
 * Konva-based Gantt chart layer for tactical PM scheduling (zoom levels 8-12).
 * Renders PM blocks, constraint walls, train labels, and timeline axis.
 *
 * Features:
 * - PM blocks with status-based colors
 * - Compliance window constraint walls
 * - Train labels on the left
 * - Week/day timeline axis at top
 * - Drag-and-drop PM rescheduling (with constraint validation)
 * - Hover tooltips
 *
 * @see specs/006-user-interface.md Section 6.3.3
 */

import { useRef } from 'react';
import { Stage, Layer, Rect, Text, Line, Group } from 'react-konva';
import type { KonvaEventObject } from 'konva/lib/Node';
import type { Stage as StageType } from 'konva/lib/Stage';

import type { PmBlock, ConstraintWall, TacticalCanvasData, DragValidationState, BaselineShadowData } from './types';
import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';

/** Baseline shadow block colors by status */
const BASELINE_SHADOW_COLORS = {
  UNCHANGED: 'rgba(156, 163, 175, 0.2)', // Gray, nearly invisible
  MOVED: 'rgba(234, 179, 8, 0.3)', // Yellow/amber for moved
  ADDED: 'rgba(34, 197, 94, 0.3)', // Green for added
  REMOVED: 'rgba(239, 68, 68, 0.3)', // Red for removed
};

// =============================================================================
// Constants
// =============================================================================

/** Layout constants for the Gantt chart */
const LAYOUT = {
  HEADER_HEIGHT: 48,
  TRAIN_LABEL_WIDTH: 120,
  ROW_HEIGHT: 40,
  PM_BLOCK_HEIGHT: 28,
  PM_BLOCK_MARGIN: 6,
  DAY_WIDTH: 24,
  WEEK_WIDTH: 24 * 7,
  MIN_PM_WIDTH: 20,
  CONSTRAINT_WALL_WIDTH: 2,
  GRID_LINE_COLOR: '#e2e8f0',
  HEADER_BG: '#f8fafc',
  TRAIN_LABEL_BG: '#ffffff',
  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
};

/** PM status to color mapping */
function getPmColor(status: string): string {
  switch (status) {
    case 'SCHEDULED':
      return PM_STATUS_COLORS.scheduled;
    case 'IN_PROGRESS':
      return PM_STATUS_COLORS.inProgress;
    case 'COMPLETED':
      return PM_STATUS_COLORS.completed;
    case 'CANCELLED':
      return PM_STATUS_COLORS.cancelled;
    case 'DEFERRED':
      return PM_STATUS_COLORS.deferred;
    default:
      return PM_STATUS_COLORS.scheduled;
  }
}

// =============================================================================
// Types
// =============================================================================

export interface TacticalGanttLayerProps {
  data: TacticalCanvasData | null;
  trainOrder: string[];
  fromDate: Date;
  toDate: Date;
  width: number;
  height: number;
  selectedPmIds: string[];
  /** ID of the PM currently being dragged (if any) */
  draggingPmId?: string | null;
  /** Validation state for the current drag operation */
  dragValidation?: DragValidationState | null;
  /** Baseline shadow data for showing PM positions from baseline */
  baselineShadowData?: BaselineShadowData | null;
  onPmClick?: (pmId: string) => void;
  onPmHover?: (pm: PmBlock | null) => void;
  /** Called when drag starts - includes source date */
  onPmDragStart?: (pmId: string, sourceDate: string) => void;
  /** Called during drag as position changes - for real-time validation */
  onPmDragMove?: (pmId: string, targetDate: string) => void;
  /** Called when drag ends - for final commit/cancel */
  onPmDragEnd?: (pmId: string, newDate: string) => void;
  showConstraintWalls?: boolean;
  showGrid?: boolean;
}

interface DayData {
  date: Date;
  dateStr: string;
  dayOfWeek: number;
  isWeekStart: boolean;
  isToday: boolean;
}

interface WeekData {
  weekStart: Date;
  weekNum: number;
  daysInWeek: number;
}

// =============================================================================
// Pure Utility Functions
// =============================================================================

function getDays(fromDate: Date, toDate: Date): DayData[] {
  const days: DayData[] = [];
  const current = new Date(fromDate);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  while (current <= toDate) {
    const dayOfWeek = current.getDay();
    days.push({
      date: new Date(current),
      dateStr: current.toISOString().split('T')[0],
      dayOfWeek,
      isWeekStart: dayOfWeek === 0,
      isToday: current.getTime() === today.getTime(),
    });
    current.setDate(current.getDate() + 1);
  }
  return days;
}

function getWeeks(days: DayData[]): WeekData[] {
  const weeks: WeekData[] = [];
  let currentWeek: WeekData | null = null;

  for (const day of days) {
    if (day.isWeekStart || currentWeek === null) {
      if (currentWeek) {
        weeks.push(currentWeek);
      }
      const weekNum = getWeekNumber(day.date);
      currentWeek = { weekStart: day.date, weekNum, daysInWeek: 1 };
    } else {
      currentWeek.daysInWeek++;
    }
  }
  if (currentWeek) {
    weeks.push(currentWeek);
  }
  return weeks;
}

function getWeekNumber(date: Date): number {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  return Math.ceil(((d.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);
}

function dateDiffDays(a: Date, b: Date): number {
  return Math.floor((a.getTime() - b.getTime()) / (1000 * 60 * 60 * 24));
}

function parseDate(dateStr: string): Date {
  return new Date(dateStr + 'T00:00:00');
}

function buildTrainIndexMap(trainOrder: string[]): Map<string, number> {
  const map = new Map<string, number>();
  trainOrder.forEach((id, i) => map.set(id, i));
  return map;
}

function buildTrainMetadata(pmBlocks: PmBlock[]): { numbers: Map<string, string>; fleets: Map<string, string> } {
  const numbers = new Map<string, string>();
  const fleets = new Map<string, string>();

  for (const pm of pmBlocks) {
    if (!numbers.has(pm.trainId)) {
      numbers.set(pm.trainId, pm.trainNumber);
      const code = pm.trainNumber.split('-')[0] || 'KS';
      fleets.set(pm.trainId, code);
    }
  }

  return { numbers, fleets };
}

// =============================================================================
// Sub-Components
// =============================================================================

interface TimelineHeaderProps {
  days: DayData[];
  weeks: WeekData[];
  offsetX: number;
}

function TimelineHeader({ days, weeks, offsetX }: TimelineHeaderProps) {
  return (
    <Group x={offsetX} y={0}>
      {/* Week row */}
      <Rect
        x={0}
        y={0}
        width={days.length * LAYOUT.DAY_WIDTH}
        height={LAYOUT.HEADER_HEIGHT / 2}
        fill={LAYOUT.HEADER_BG}
      />
      {weeks.map((week, i) => {
        const x = days.findIndex((d) => d.date.getTime() === week.weekStart.getTime()) * LAYOUT.DAY_WIDTH;
        const width = week.daysInWeek * LAYOUT.DAY_WIDTH;
        return (
          <Group key={i} x={x} y={0}>
            <Rect
              width={width}
              height={LAYOUT.HEADER_HEIGHT / 2}
              stroke={LAYOUT.GRID_LINE_COLOR}
              strokeWidth={1}
            />
            <Text
              x={4}
              y={6}
              text={`Week ${week.weekNum}`}
              fontSize={11}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#64748b"
            />
          </Group>
        );
      })}

      {/* Day row */}
      {days.map((day, i) => (
        <Group key={day.dateStr} x={i * LAYOUT.DAY_WIDTH} y={LAYOUT.HEADER_HEIGHT / 2}>
          <Rect
            width={LAYOUT.DAY_WIDTH}
            height={LAYOUT.HEADER_HEIGHT / 2}
            fill={day.isToday ? '#dbeafe' : day.dayOfWeek === 0 || day.dayOfWeek === 6 ? '#f1f5f9' : LAYOUT.HEADER_BG}
            stroke={LAYOUT.GRID_LINE_COLOR}
            strokeWidth={0.5}
          />
          <Text
            x={2}
            y={6}
            text={['S', 'M', 'T', 'W', 'T', 'F', 'S'][day.dayOfWeek]}
            fontSize={9}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill={day.isToday ? '#2563eb' : '#94a3b8'}
          />
          <Text
            x={2}
            y={15}
            text={String(day.date.getDate())}
            fontSize={9}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill={day.isToday ? '#2563eb' : '#64748b'}
            fontStyle={day.isToday ? 'bold' : 'normal'}
          />
        </Group>
      ))}
    </Group>
  );
}

interface TrainLabelsPanelProps {
  trainOrder: string[];
  trainNumbers: Map<string, string>;
  fleetCodes: Map<string, string>;
}

function TrainLabelsPanel({ trainOrder, trainNumbers, fleetCodes }: TrainLabelsPanelProps) {
  return (
    <Group x={0} y={LAYOUT.HEADER_HEIGHT}>
      <Rect
        width={LAYOUT.TRAIN_LABEL_WIDTH}
        height={trainOrder.length * LAYOUT.ROW_HEIGHT}
        fill={LAYOUT.TRAIN_LABEL_BG}
      />
      {trainOrder.map((trainId, i) => {
        const trainNumber = trainNumbers.get(trainId) || trainId.slice(0, 8);
        const fleetCode = fleetCodes.get(trainId) || 'KS';
        const fleetColor = FLEET_COLORS[fleetCode as keyof typeof FLEET_COLORS] || FLEET_COLORS.KS;

        return (
          <Group key={trainId} y={i * LAYOUT.ROW_HEIGHT}>
            <Rect
              width={LAYOUT.TRAIN_LABEL_WIDTH}
              height={LAYOUT.ROW_HEIGHT}
              stroke={LAYOUT.GRID_LINE_COLOR}
              strokeWidth={0.5}
            />
            <Rect
              x={4}
              y={10}
              width={4}
              height={LAYOUT.ROW_HEIGHT - 20}
              fill={fleetColor}
              cornerRadius={2}
            />
            <Text
              x={14}
              y={12}
              text={trainNumber}
              fontSize={12}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#1e293b"
              fontStyle="bold"
            />
            <Text
              x={14}
              y={26}
              text={fleetCode}
              fontSize={10}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#64748b"
            />
          </Group>
        );
      })}
    </Group>
  );
}

interface GanttGridProps {
  days: DayData[];
  rowCount: number;
  offsetX: number;
}

function GanttGrid({ days, rowCount, offsetX }: GanttGridProps) {
  const weekStartDays = days.filter((d) => d.isWeekStart);
  const todayIndex = days.findIndex((d) => d.isToday);

  return (
    <Group x={offsetX} y={LAYOUT.HEADER_HEIGHT}>
      {/* Row backgrounds */}
      {Array.from({ length: rowCount }).map((_, i) => (
        <Rect
          key={i}
          y={i * LAYOUT.ROW_HEIGHT}
          width={days.length * LAYOUT.DAY_WIDTH}
          height={LAYOUT.ROW_HEIGHT}
          fill={i % 2 === 0 ? '#ffffff' : '#fafafa'}
          stroke={LAYOUT.GRID_LINE_COLOR}
          strokeWidth={0.5}
        />
      ))}

      {/* Day columns - today highlight */}
      {todayIndex >= 0 && (
        <Rect
          x={todayIndex * LAYOUT.DAY_WIDTH}
          y={0}
          width={LAYOUT.DAY_WIDTH}
          height={rowCount * LAYOUT.ROW_HEIGHT}
          fill="rgba(37, 99, 235, 0.05)"
        />
      )}

      {/* Week separators */}
      {weekStartDays.map((day) => {
        const x = days.indexOf(day) * LAYOUT.DAY_WIDTH;
        return (
          <Line
            key={`week-${day.dateStr}`}
            points={[x, 0, x, rowCount * LAYOUT.ROW_HEIGHT]}
            stroke="#cbd5e1"
            strokeWidth={1}
          />
        );
      })}

      {/* Today line */}
      {todayIndex >= 0 && (
        <Line
          points={[
            todayIndex * LAYOUT.DAY_WIDTH,
            0,
            todayIndex * LAYOUT.DAY_WIDTH,
            rowCount * LAYOUT.ROW_HEIGHT,
          ]}
          stroke="#2563eb"
          strokeWidth={2}
          dash={[4, 4]}
        />
      )}
    </Group>
  );
}

interface PmBlockRectProps {
  pm: PmBlock;
  x: number;
  y: number;
  width: number;
  isSelected: boolean;
  isDragging?: boolean;
  dragValidation?: DragValidationState | null;
  onHover?: (pm: PmBlock | null) => void;
  onClick?: (pmId: string) => void;
  onDragStart?: (pmId: string, sourceDate: string) => void;
  onDragMove?: (pmId: string, targetDate: string) => void;
  onDragEnd?: (pmId: string, newDate: string) => void;
  fromDate: Date;
}

function PmBlockRect({
  pm,
  x,
  y,
  width,
  isSelected,
  isDragging,
  dragValidation,
  onHover,
  onClick,
  onDragStart,
  onDragMove,
  onDragEnd,
  fromDate,
}: PmBlockRectProps) {
  const color = pm.displayColor || getPmColor(pm.status);
  const finalWidth = Math.max(width, LAYOUT.MIN_PM_WIDTH);

  const handleDragStart = () => {
    if (onDragStart) {
      onDragStart(pm.pmId, pm.targetDate);
    }
  };

  const handleDragMove = (e: KonvaEventObject<DragEvent>) => {
    if (onDragMove) {
      const newX = e.target.x();
      const dayOffset = Math.round(newX / LAYOUT.DAY_WIDTH);
      const newDate = new Date(fromDate);
      newDate.setDate(newDate.getDate() + dayOffset);
      onDragMove(pm.pmId, newDate.toISOString().split('T')[0]);
    }
  };

  const handleDragEnd = (e: KonvaEventObject<DragEvent>) => {
    if (onDragEnd) {
      const newX = e.target.x();
      const dayOffset = Math.round(newX / LAYOUT.DAY_WIDTH);
      const newDate = new Date(fromDate);
      newDate.setDate(newDate.getDate() + dayOffset);
      onDragEnd(pm.pmId, newDate.toISOString().split('T')[0]);
    }
  };

  // Determine border color based on drag validation state
  let borderColor = isSelected ? '#1d4ed8' : '#00000015';
  let borderWidth = 1;
  let shadowBlur = 2;

  if (isDragging && dragValidation) {
    if (dragValidation.isValid) {
      // Valid drop - green outline
      borderColor = '#22c55e'; // Green-500
      borderWidth = 3;
      shadowBlur = 8;
    } else {
      // Invalid drop - red outline
      borderColor = '#ef4444'; // Red-500
      borderWidth = 3;
      shadowBlur = 8;
    }
  }

  return (
    <Group
      x={x}
      y={y}
      draggable={!pm.isLocked}
      onDragStart={handleDragStart}
      onDragMove={handleDragMove}
      onDragEnd={handleDragEnd}
      onMouseEnter={() => onHover?.(pm)}
      onMouseLeave={() => onHover?.(null)}
      onClick={() => onClick?.(pm.pmId)}
    >
      {/* Shadow for selected or dragging */}
      {(isSelected || isDragging) && (
        <Rect
          x={-3}
          y={-3}
          width={finalWidth + 6}
          height={LAYOUT.PM_BLOCK_HEIGHT + 6}
          fill="transparent"
          stroke={isDragging && dragValidation
            ? (dragValidation.isValid ? '#22c55e' : '#ef4444')
            : '#3b82f6'
          }
          strokeWidth={isDragging ? 3 : 2}
          cornerRadius={6}
          dash={isDragging ? undefined : undefined}
          opacity={isDragging ? 0.8 : 1}
        />
      )}

      {/* Drag validation indicator glow */}
      {isDragging && dragValidation && (
        <Rect
          x={-6}
          y={-6}
          width={finalWidth + 12}
          height={LAYOUT.PM_BLOCK_HEIGHT + 12}
          fill="transparent"
          stroke={dragValidation.isValid ? 'rgba(34, 197, 94, 0.3)' : 'rgba(239, 68, 68, 0.3)'}
          strokeWidth={8}
          cornerRadius={10}
        />
      )}

      {/* PM block */}
      <Rect
        width={finalWidth}
        height={LAYOUT.PM_BLOCK_HEIGHT}
        fill={color}
        stroke={borderColor}
        strokeWidth={borderWidth}
        cornerRadius={4}
        shadowColor={isDragging ? (dragValidation?.isValid ? '#22c55e' : '#ef4444') : '#000'}
        shadowBlur={shadowBlur}
        shadowOpacity={isDragging ? 0.4 : 0.1}
        shadowOffsetY={isDragging ? 4 : 1}
      />

      {/* Lock indicator */}
      {pm.isLocked && (
        <Text
          x={4}
          y={7}
          text="🔒"
          fontSize={10}
        />
      )}

      {/* PM code label */}
      <Text
        x={pm.isLocked ? 18 : 6}
        y={7}
        text={pm.pmCode}
        fontSize={11}
        fontFamily={LAYOUT.FONT_FAMILY}
        fill="#ffffff"
        fontStyle="bold"
      />

      {/* Duration label (if space) */}
      {finalWidth > 50 && pm.estimatedHours && (
        <Text
          x={finalWidth - 30}
          y={8}
          text={`${pm.estimatedHours}h`}
          fontSize={9}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="rgba(255,255,255,0.8)"
        />
      )}

      {/* Drag validation status icon */}
      {isDragging && dragValidation && (
        <Group x={finalWidth - 16} y={-8}>
          <Rect
            width={20}
            height={20}
            fill={dragValidation.isValid ? '#22c55e' : '#ef4444'}
            cornerRadius={10}
            shadowColor="#000"
            shadowBlur={4}
            shadowOpacity={0.3}
          />
          <Text
            x={4}
            y={3}
            text={dragValidation.isValid ? '✓' : '✗'}
            fontSize={12}
            fill="#ffffff"
            fontStyle="bold"
          />
        </Group>
      )}
    </Group>
  );
}

interface ConstraintWallsLayerProps {
  walls: ConstraintWall[];
  trainOrder: string[];
  days: DayData[];
  pmBlocks: PmBlock[];
  offsetX: number;
}

function ConstraintWallsLayer({ walls, trainOrder, days, pmBlocks, offsetX }: ConstraintWallsLayerProps) {
  const trainIndexMap = buildTrainIndexMap(trainOrder);
  const pmBlockMap = new Map<string, PmBlock>();
  pmBlocks.forEach((pm) => pmBlockMap.set(pm.pmId, pm));

  return (
    <Group x={offsetX} y={LAYOUT.HEADER_HEIGHT}>
      {walls.map((wall) => {
        const pm = pmBlockMap.get(wall.pmId);
        if (!pm) return null;

        const trainIndex = trainIndexMap.get(pm.trainId);
        if (trainIndex === undefined) return null;

        const dayIndex = days.findIndex((d) => d.dateStr === wall.date);
        if (dayIndex < 0) return null;

        const x = dayIndex * LAYOUT.DAY_WIDTH;
        const y = trainIndex * LAYOUT.ROW_HEIGHT;
        const color = wall.type === 'COMPLIANCE_START'
          ? CONSTRAINT_COLORS.approaching
          : CONSTRAINT_COLORS.hardViolation;

        return (
          <Line
            key={`${wall.pmId}-${wall.type}`}
            points={[x, y + 4, x, y + LAYOUT.ROW_HEIGHT - 4]}
            stroke={color}
            strokeWidth={LAYOUT.CONSTRAINT_WALL_WIDTH}
            dash={[4, 2]}
          />
        );
      })}
    </Group>
  );
}

// =============================================================================
// Main Component
// =============================================================================

export function TacticalGanttLayer({
  data,
  trainOrder,
  fromDate,
  toDate,
  width,
  height,
  selectedPmIds,
  draggingPmId,
  dragValidation,
  baselineShadowData,
  onPmClick,
  onPmHover,
  onPmDragStart,
  onPmDragMove,
  onPmDragEnd,
  showConstraintWalls = true,
  showGrid = true,
}: TacticalGanttLayerProps) {
  const stageRef = useRef<StageType>(null);

  if (!data) {
    return null;
  }

  // Compute derived data inline (no useMemo - pure functions)
  const days = getDays(fromDate, toDate);
  const weeks = getWeeks(days);
  const trainIndexMap = buildTrainIndexMap(trainOrder);
  const { numbers: trainNumbers, fleets: fleetCodes } = buildTrainMetadata(data.pmBlocks);
  const selectedSet = new Set(selectedPmIds);

  const gridOffsetX = LAYOUT.TRAIN_LABEL_WIDTH;
  const contentWidth = days.length * LAYOUT.DAY_WIDTH + gridOffsetX;
  const contentHeight = trainOrder.length * LAYOUT.ROW_HEIGHT + LAYOUT.HEADER_HEIGHT;

  return (
    <Stage
      ref={stageRef}
      width={width}
      height={height}
      style={{ backgroundColor: '#f8fafc' }}
    >
      {/* Background layer */}
      <Layer>
        <Rect width={contentWidth} height={contentHeight} fill="#ffffff" />
      </Layer>

      {/* Grid layer */}
      {showGrid && (
        <Layer>
          <GanttGrid days={days} rowCount={trainOrder.length} offsetX={gridOffsetX} />
        </Layer>
      )}

      {/* Constraint walls layer */}
      {showConstraintWalls && data.constraintWalls.length > 0 && (
        <Layer>
          <ConstraintWallsLayer
            walls={data.constraintWalls}
            trainOrder={trainOrder}
            days={days}
            pmBlocks={data.pmBlocks}
            offsetX={gridOffsetX}
          />
        </Layer>
      )}

      {/* Baseline shadow layer (shows PM positions from baseline) */}
      {baselineShadowData && baselineShadowData.pmBlocks.length > 0 && (
        <Layer>
          <Group x={gridOffsetX} y={LAYOUT.HEADER_HEIGHT}>
            {baselineShadowData.pmBlocks.map((bpm) => {
              const trainIndex = trainIndexMap.get(bpm.trainId);
              if (trainIndex === undefined) return null;

              const baselineDate = parseDate(bpm.baselineDate);
              const dayOffset = dateDiffDays(baselineDate, fromDate);
              if (dayOffset < 0 || dayOffset >= days.length) return null;

              const x = dayOffset * LAYOUT.DAY_WIDTH;
              const y = trainIndex * LAYOUT.ROW_HEIGHT + LAYOUT.PM_BLOCK_MARGIN;
              const blockWidth = LAYOUT.DAY_WIDTH * 2 - 4; // Default 2-day width for shadow

              // Get color based on drift status
              const shadowColor = BASELINE_SHADOW_COLORS[bpm.status] || BASELINE_SHADOW_COLORS.UNCHANGED;

              // For MOVED PMs, draw a dashed outline where it was in baseline
              if (bpm.status === 'MOVED' || bpm.status === 'REMOVED') {
                return (
                  <Group key={`baseline-${bpm.pmId}`}>
                    {/* Shadow fill */}
                    <Rect
                      x={x}
                      y={y}
                      width={blockWidth}
                      height={LAYOUT.PM_BLOCK_HEIGHT}
                      fill={shadowColor}
                      cornerRadius={4}
                    />
                    {/* Dashed border */}
                    <Rect
                      x={x}
                      y={y}
                      width={blockWidth}
                      height={LAYOUT.PM_BLOCK_HEIGHT}
                      stroke={bpm.status === 'REMOVED' ? '#EF4444' : '#F59E0B'}
                      strokeWidth={1.5}
                      dash={[4, 2]}
                      cornerRadius={4}
                    />
                    {/* PM code label */}
                    <Text
                      x={x + 4}
                      y={y + 6}
                      text={bpm.pmCode}
                      fontSize={10}
                      fontFamily={LAYOUT.FONT_FAMILY}
                      fill={bpm.status === 'REMOVED' ? '#DC2626' : '#D97706'}
                      opacity={0.7}
                    />
                  </Group>
                );
              }

              // For ADDED PMs (new in current schedule), show green indicator
              if (bpm.status === 'ADDED') {
                return (
                  <Rect
                    key={`baseline-${bpm.pmId}`}
                    x={x - 2}
                    y={y - 2}
                    width={4}
                    height={LAYOUT.PM_BLOCK_HEIGHT + 4}
                    fill="#22C55E"
                    cornerRadius={2}
                    opacity={0.6}
                  />
                );
              }

              // UNCHANGED - very subtle indicator
              return null;
            })}
          </Group>
        </Layer>
      )}

      {/* PM blocks layer */}
      <Layer>
        <Group x={gridOffsetX} y={LAYOUT.HEADER_HEIGHT}>
          {data.pmBlocks.map((pm) => {
            const trainIndex = trainIndexMap.get(pm.trainId);
            if (trainIndex === undefined) return null;

            const pmDate = parseDate(pm.targetDate);
            const dayOffset = dateDiffDays(pmDate, fromDate);
            if (dayOffset < 0 || dayOffset >= days.length) return null;

            const x = dayOffset * LAYOUT.DAY_WIDTH;
            const y = trainIndex * LAYOUT.ROW_HEIGHT + LAYOUT.PM_BLOCK_MARGIN;
            const blockWidth = pm.durationDays * LAYOUT.DAY_WIDTH - 4;

            return (
              <PmBlockRect
                key={pm.pmId}
                pm={pm}
                x={x}
                y={y}
                width={blockWidth}
                isSelected={selectedSet.has(pm.pmId)}
                isDragging={draggingPmId === pm.pmId}
                dragValidation={draggingPmId === pm.pmId ? dragValidation : null}
                onHover={onPmHover}
                onClick={onPmClick}
                onDragStart={onPmDragStart}
                onDragMove={onPmDragMove}
                onDragEnd={onPmDragEnd}
                fromDate={fromDate}
              />
            );
          })}
        </Group>
      </Layer>

      {/* Timeline header layer (on top) */}
      <Layer>
        <TimelineHeader days={days} weeks={weeks} offsetX={gridOffsetX} />
      </Layer>

      {/* Train labels layer (fixed left) */}
      <Layer>
        <TrainLabelsPanel
          trainOrder={trainOrder}
          trainNumbers={trainNumbers}
          fleetCodes={fleetCodes}
        />
      </Layer>
    </Stage>
  );
}

export default TacticalGanttLayer;

content.content:
     1→/**
     2→ * Tactical Wide Layer
     3→ *
     4→ * deck.gl WebGL layer for the 1-year tactical-wide PM view.
     5→ * Renders compressed Gantt blocks at monthly granularity:
     6→ * - Rows = trains
     7→ * - Columns = months
     8→ * - Blocks = PM events compressed by month
     9→ *
    10→ * Used at zoom levels 4-8 (TACTICAL_WIDE).
    11→ * Bridges the gap between strategic heatmap and tactical Gantt.
    12→ *
    13→ * @see specs/006-user-interface.md Section 6.3
    14→ */
    15→
    16→import { PolygonLayer, TextLayer } from '@deck.gl/layers';
    17→import DeckGL from '@deck.gl/react';
    18→import { OrthographicView } from '@deck.gl/core';
    19→
    20→import type { TacticalWideCanvasData } from './types';
    21→
    22→// =============================================================================
    23→// Constants
    24→// =============================================================================
    25→
    26→const MONTH_WIDTH = 100;
    27→const ROW_HEIGHT = 36;
    28→const BLOCK_HEIGHT = 24;
    29→const BLOCK_MARGIN = 2;
    30→const LABEL_WIDTH = 120;
    31→const HEADER_HEIGHT = 50;
    32→
    33→/** PM status colors (RGBA) matching spec 006.3.4 */
    34→const PM_STATUS_COLORS: Record<string, [number, number, number, number]> = {
    35→  SCHEDULED: [59, 130, 246, 255],    // Blue-500
    36→  IN_PROGRESS: [245, 158, 11, 255],  // Amber-500
    37→  COMPLETED: [34, 197, 94, 255],     // Green-500
    38→  CANCELLED: [148, 163, 184, 255],   // Slate-400
    39→  DEFERRED: [168, 85, 247, 255],     // Purple-500
    40→  OVERDUE: [239, 68, 68, 255],       // Red-500
    41→};
    42→
    43→/** Fleet colors */
    44→const FLEET_COLORS: Record<string, [number, number, number, number]> = {
    45→  KS: [14, 165, 233, 255],
    46→  ALSTOM: [139, 92, 246, 255],
    47→  DEFAULT: [100, 116, 139, 255],
    48→};
    49→
    50→/** Month names for labels */
    51→const MONTH_NAMES = [
    52→  'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
    53→  'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
    54→];
    55→
    56→// =============================================================================
    57→// Helper Types
    58→// =============================================================================
    59→
    60→interface CompressedBlock {
    61→  pmId: string;
    62→  trainId: string;
    63→  trainNumber: string;
    64→  trainIndex: number;
    65→  monthIndex: number;
    66→  pmCode: string;
    67→  targetDate: string;
    68→  status: string;
    69→  isLocked: boolean;
    70→  weekOfMonth: number;
    71→  durationWeeks: number;
    72→  displayColor: string;
    73→  polygon: [number, number][];
    74→}
    75→
    76→interface MonthLabel {
    77→  text: string;
    78→  month: number;
    79→  year: number;
    80→  position: [number, number];
    81→}
    82→
    83→interface TrainLabel {
    84→  text: string;
    85→  trainId: string;
    86→  fleetCode: string;
    87→  position: [number, number];
    88→}
    89→
    90→// =============================================================================
    91→// Helper Functions
    92→// =============================================================================
    93→
    94→/**
    95→ * Get the week of the month for a date (1-5)
    96→ */
    97→function getWeekOfMonth(dateStr: string): number {
    98→  const date = new Date(dateStr);
    99→  const day = date.getDate();
   100→  return Math.ceil(day / 7);
   101→}
   102→
   103→/**
   104→ * Generate months between two dates
   105→ */
   106→function generateMonths(fromDate: Date, toDate: Date): Array<{ month: number; year: number }> {
   107→  const months: Array<{ month: number; year: number }> = [];
   108→  const current = new Date(fromDate.getFullYear(), fromDate.getMonth(), 1);
   109→  const end = new Date(toDate.getFullYear(), toDate.getMonth(), 1);
   110→
   111→  while (current <= end) {
   112→    months.push({ month: current.getMonth(), year: current.getFullYear() });
   113→    current.setMonth(current.getMonth() + 1);
   114→  }
   115→
   116→  return months;
   117→}
   118→
   119→/**
   120→ * Get month index from date string
   121→ */
   122→function getMonthIndex(dateStr: string, fromDate: Date): number {
   123→  const date = new Date(dateStr);
   124→  const yearDiff = date.getFullYear() - fromDate.getFullYear();
   125→  const monthDiff = date.getMonth() - fromDate.getMonth();
   126→  return yearDiff * 12 + monthDiff;
   127→}
   128→
   129→/**
   130→ * Calculate weeks duration from days
   131→ */
   132→function daysToWeeks(days: number): number {
   133→  return Math.max(1, Math.ceil(days / 7));
   134→}
   135→
   136→/**
   137→ * Get color for PM status
   138→ */
   139→function getStatusColor(status: string): [number, number, number, number] {
   140→  return PM_STATUS_COLORS[status] || PM_STATUS_COLORS.SCHEDULED;
   141→}
   142→
   143→/**
   144→ * Create polygon vertices for a compressed block
   145→ */
   146→function createBlockPolygon(
   147→  monthIndex: number,
   148→  trainIndex: number,
   149→  weekOfMonth: number,
   150→  durationWeeks: number
   151→): [number, number][] {
   152→  const weekWidth = MONTH_WIDTH / 5; // 5 weeks max per month
   153→  const x = LABEL_WIDTH + monthIndex * MONTH_WIDTH + (weekOfMonth - 1) * weekWidth + BLOCK_MARGIN;
   154→  const y = HEADER_HEIGHT + trainIndex * ROW_HEIGHT + (ROW_HEIGHT - BLOCK_HEIGHT) / 2;
   155→  const width = Math.min(durationWeeks * weekWidth - BLOCK_MARGIN * 2, MONTH_WIDTH - BLOCK_MARGIN * 2);
   156→  const height = BLOCK_HEIGHT;
   157→
   158→  return [
   159→    [x, y],
   160→    [x + width, y],
   161→    [x + width, y + height],
   162→    [x, y + height],
   163→  ];
   164→}
   165→
   166→/**
   167→ * Transform API data into compressed blocks
   168→ */
   169→function transformToCompressedBlocks(
   170→  data: TacticalWideCanvasData,
   171→  fromDate: Date
   172→): CompressedBlock[] {
   173→  const blocks: CompressedBlock[] = [];
   174→  const trainIndexMap = new Map<string, number>();
   175→
   176→  // Build train index map
   177→  data.trains.forEach((train, index) => {
   178→    trainIndexMap.set(train.trainId, index);
   179→  });
   180→
   181→  // Create compressed blocks
   182→  data.pmBlocks.forEach((pm) => {
   183→    const trainIndex = trainIndexMap.get(pm.trainId);
   184→    if (trainIndex === undefined) return;
   185→
   186→    const train = data.trains.find((t) => t.trainId === pm.trainId);
   187→    if (!train) return;
   188→
   189→    const monthIndex = getMonthIndex(pm.targetDate, fromDate);
   190→    const weekOfMonth = getWeekOfMonth(pm.targetDate);
   191→    const durationWeeks = daysToWeeks(pm.durationDays);
   192→
   193→    blocks.push({
   194→      pmId: pm.pmId,
   195→      trainId: pm.trainId,
   196→      trainNumber: train.trainNumber,
   197→      trainIndex,
   198→      monthIndex,
   199→      pmCode: pm.pmCode,
   200→      targetDate: pm.targetDate,
   201→      status: pm.status,
   202→      isLocked: pm.isLocked,
   203→      weekOfMonth,
   204→      durationWeeks,
   205→      displayColor: pm.displayColor,
   206→      polygon: createBlockPolygon(monthIndex, trainIndex, weekOfMonth, durationWeeks),
   207→    });
   208→  });
   209→
   210→  return blocks;
   211→}
   212→
   213→// =============================================================================
   214→// Component Props
   215→// =============================================================================
   216→
   217→export interface TacticalWideLayerProps {
   218→  data: TacticalWideCanvasData | null;
   219→  fromDate: Date;
   220→  toDate: Date;
   221→  width: number | string;
   222→  height: number | string;
   223→  selectedPmIds?: string[];
   224→  onBlockHover?: (block: CompressedBlock | null) => void;
   225→  onBlockClick?: (block: CompressedBlock) => void;
   226→  onMonthClick?: (month: number, year: number) => void;
   227→}
   228→
   229→// =============================================================================
   230→// Component
   231→// =============================================================================
   232→
   233→/**
   234→ * Tactical Wide View
   235→ *
   236→ * Renders compressed PM blocks at monthly granularity using deck.gl.
   237→ * Optimized for 60fps rendering when viewing a full year of data.
   238→ */
   239→export function TacticalWideLayer({
   240→  data,
   241→  fromDate,
   242→  toDate,
   243→  width,
   244→  height,
   245→  selectedPmIds = [],
   246→  onBlockHover,
   247→  onBlockClick,
   248→  onMonthClick,
   249→}: TacticalWideLayerProps) {
   250→  if (!data || data.trains.length === 0) {
   251→    return (
   252→      <div
   253→        style={{
   254→          width,
   255→          height,
   256→          display: 'flex',
   257→          alignItems: 'center',
   258→          justifyContent: 'center',
   259→          color: 'var(--pt-text-muted)',
   260→        }}
   261→      >
   262→        No tactical-wide data available
   263→      </div>
   264→    );
   265→  }
   266→
   267→  const months = generateMonths(fromDate, toDate);
   268→  const blocks = transformToCompressedBlocks(data, fromDate);
   269→  const trainCount = data.trains.length;
   270→
   271→  const canvasWidth = LABEL_WIDTH + months.length * MONTH_WIDTH + 40;
   272→  const canvasHeight = HEADER_HEIGHT + trainCount * ROW_HEIGHT + 40;
   273→
   274→  // Generate month labels
   275→  const monthLabels: MonthLabel[] = months.map((m, index) => ({
   276→    text: `${MONTH_NAMES[m.month]} ${m.year}`,
   277→    month: m.month,
   278→    year: m.year,
   279→    position: [
   280→      LABEL_WIDTH + index * MONTH_WIDTH + MONTH_WIDTH / 2,
   281→      HEADER_HEIGHT / 2,
   282→    ] as [number, number],
   283→  }));
   284→
   285→  // Generate train labels
   286→  const trainLabels: TrainLabel[] = data.trains.map((train, index) => ({
   287→    text: train.trainNumber,
   288→    trainId: train.trainId,
   289→    fleetCode: train.fleetCode,
   290→    position: [
   291→      LABEL_WIDTH / 2,
   292→      HEADER_HEIGHT + index * ROW_HEIGHT + ROW_HEIGHT / 2,
   293→    ] as [number, number],
   294→  }));
   295→
   296→  // Create grid lines for months
   297→  const gridLines: Array<{ polygon: [number, number][] }> = months.map((_, index) => {
   298→    const x = LABEL_WIDTH + index * MONTH_WIDTH;
   299→    return {
   300→      polygon: [
   301→        [x, HEADER_HEIGHT],
   302→        [x + 1, HEADER_HEIGHT],
   303→        [x + 1, HEADER_HEIGHT + trainCount * ROW_HEIGHT],
   304→        [x, HEADER_HEIGHT + trainCount * ROW_HEIGHT],
   305→      ] as [number, number][],
   306→    };
   307→  });
   308→
   309→  // Create row lines for trains
   310→  const rowLines: Array<{ polygon: [number, number][] }> = data.trains.map((_, index) => {
   311→    const y = HEADER_HEIGHT + index * ROW_HEIGHT;
   312→    return {
   313→      polygon: [
   314→        [LABEL_WIDTH, y],
   315→        [LABEL_WIDTH + months.length * MONTH_WIDTH, y],
   316→        [LABEL_WIDTH + months.length * MONTH_WIDTH, y + 1],
   317→        [LABEL_WIDTH, y + 1],
   318→      ] as [number, number][],
   319→    };
   320→  });
   321→
   322→  const layers = [
   323→    // Grid lines - months
   324→    new PolygonLayer<{ polygon: [number, number][] }>({
   325→      id: 'month-grid',
   326→      data: gridLines,
   327→      pickable: false,
   328→      filled: true,
   329→      getPolygon: (d) => d.polygon,
   330→      getFillColor: [226, 232, 240, 255], // Slate-200
   331→    }),
   332→
   333→    // Grid lines - rows
   334→    new PolygonLayer<{ polygon: [number, number][] }>({
   335→      id: 'row-grid',
   336→      data: rowLines,
   337→      pickable: false,
   338→      filled: true,
   339→      getPolygon: (d) => d.polygon,
   340→      getFillColor: [241, 245, 249, 255], // Slate-100
   341→    }),
   342→
   343→    // PM Blocks
   344→    new PolygonLayer<CompressedBlock>({
   345→      id: 'pm-blocks',
   346→      data: blocks,
   347→      pickable: true,
   348→      filled: true,
   349→      stroked: true,
   350→      extruded: false,
   351→      getPolygon: (d) => d.polygon,
   352→      getFillColor: (d) => {
   353→        const color = getStatusColor(d.status);
