/**
 * Tactical Wide Layer
 *
 * deck.gl WebGL layer for the 1-year tactical-wide PM view.
 * Renders compressed Gantt blocks at monthly granularity:
 * - Rows = trains
 * - Columns = months
 * - Blocks = PM events compressed by month
 *
 * Used at zoom levels 4-8 (TACTICAL_WIDE).
 * Bridges the gap between strategic heatmap and tactical Gantt.
 *
 * @see specs/006-user-interface.md Section 6.3
 */

import { PolygonLayer, TextLayer } from '@deck.gl/layers';
import DeckGL from '@deck.gl/react';
import { OrthographicView } from '@deck.gl/core';

import type { TacticalWideCanvasData } from './types';

// =============================================================================
// Constants
// =============================================================================

const MONTH_WIDTH = 100;
const ROW_HEIGHT = 36;
const BLOCK_HEIGHT = 24;
const BLOCK_MARGIN = 2;
const LABEL_WIDTH = 120;
const HEADER_HEIGHT = 50;

/** PM status colors (RGBA) matching spec 006.3.4 */
const PM_STATUS_COLORS: Record<string, [number, number, number, number]> = {
  SCHEDULED: [59, 130, 246, 255],    // Blue-500
  IN_PROGRESS: [245, 158, 11, 255],  // Amber-500
  COMPLETED: [34, 197, 94, 255],     // Green-500
  CANCELLED: [148, 163, 184, 255],   // Slate-400
  DEFERRED: [168, 85, 247, 255],     // Purple-500
  OVERDUE: [239, 68, 68, 255],       // Red-500
};

/** Fleet colors */
const FLEET_COLORS: Record<string, [number, number, number, number]> = {
  KS: [14, 165, 233, 255],
  ALSTOM: [139, 92, 246, 255],
  DEFAULT: [100, 116, 139, 255],
};

/** Month names for labels */
const MONTH_NAMES = [
  'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
  'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
];

// =============================================================================
// Helper Types
// =============================================================================

interface CompressedBlock {
  pmId: string;
  trainId: string;
  trainNumber: string;
  trainIndex: number;
  monthIndex: number;
  pmCode: string;
  targetDate: string;
  status: string;
  isLocked: boolean;
  weekOfMonth: number;
  durationWeeks: number;
  displayColor: string;
  polygon: [number, number][];
}

interface MonthLabel {
  text: string;
  month: number;
  year: number;
  position: [number, number];
}

interface TrainLabel {
  text: string;
  trainId: string;
  fleetCode: string;
  position: [number, number];
}

// =============================================================================
// Helper Functions
// =============================================================================

/**
 * Get the week of the month for a date (1-5)
 */
function getWeekOfMonth(dateStr: string): number {
  const date = new Date(dateStr);
  const day = date.getDate();
  return Math.ceil(day / 7);
}

/**
 * Generate months between two dates
 */
function generateMonths(fromDate: Date, toDate: Date): Array<{ month: number; year: number }> {
  const months: Array<{ month: number; year: number }> = [];
  const current = new Date(fromDate.getFullYear(), fromDate.getMonth(), 1);
  const end = new Date(toDate.getFullYear(), toDate.getMonth(), 1);

  while (current <= end) {
    months.push({ month: current.getMonth(), year: current.getFullYear() });
    current.setMonth(current.getMonth() + 1);
  }

  return months;
}

/**
 * Get month index from date string
 */
function getMonthIndex(dateStr: string, fromDate: Date): number {
  const date = new Date(dateStr);
  const yearDiff = date.getFullYear() - fromDate.getFullYear();
  const monthDiff = date.getMonth() - fromDate.getMonth();
  return yearDiff * 12 + monthDiff;
}

/**
 * Calculate weeks duration from days
 */
function daysToWeeks(days: number): number {
  return Math.max(1, Math.ceil(days / 7));
}

/**
 * Get color for PM status
 */
function getStatusColor(status: string): [number, number, number, number] {
  return PM_STATUS_COLORS[status] || PM_STATUS_COLORS.SCHEDULED;
}

/**
 * Create polygon vertices for a compressed block
 */
function createBlockPolygon(
  monthIndex: number,
  trainIndex: number,
  weekOfMonth: number,
  durationWeeks: number
): [number, number][] {
  const weekWidth = MONTH_WIDTH / 5; // 5 weeks max per month
  const x = LABEL_WIDTH + monthIndex * MONTH_WIDTH + (weekOfMonth - 1) * weekWidth + BLOCK_MARGIN;
  const y = HEADER_HEIGHT + trainIndex * ROW_HEIGHT + (ROW_HEIGHT - BLOCK_HEIGHT) / 2;
  const width = Math.min(durationWeeks * weekWidth - BLOCK_MARGIN * 2, MONTH_WIDTH - BLOCK_MARGIN * 2);
  const height = BLOCK_HEIGHT;

  return [
    [x, y],
    [x + width, y],
    [x + width, y + height],
    [x, y + height],
  ];
}

/**
 * Transform API data into compressed blocks
 */
function transformToCompressedBlocks(
  data: TacticalWideCanvasData,
  fromDate: Date
): CompressedBlock[] {
  const blocks: CompressedBlock[] = [];
  const trainIndexMap = new Map<string, number>();

  // Build train index map
  data.trains.forEach((train, index) => {
    trainIndexMap.set(train.trainId, index);
  });

  // Create compressed blocks
  data.pmBlocks.forEach((pm) => {
    const trainIndex = trainIndexMap.get(pm.trainId);
    if (trainIndex === undefined) return;

    const train = data.trains.find((t) => t.trainId === pm.trainId);
    if (!train) return;

    const monthIndex = getMonthIndex(pm.targetDate, fromDate);
    const weekOfMonth = getWeekOfMonth(pm.targetDate);
    const durationWeeks = daysToWeeks(pm.durationDays);

    blocks.push({
      pmId: pm.pmId,
      trainId: pm.trainId,
      trainNumber: train.trainNumber,
      trainIndex,
      monthIndex,
      pmCode: pm.pmCode,
      targetDate: pm.targetDate,
      status: pm.status,
      isLocked: pm.isLocked,
      weekOfMonth,
      durationWeeks,
      displayColor: pm.displayColor,
      polygon: createBlockPolygon(monthIndex, trainIndex, weekOfMonth, durationWeeks),
    });
  });

  return blocks;
}

// =============================================================================
// Component Props
// =============================================================================

export interface TacticalWideLayerProps {
  data: TacticalWideCanvasData | null;
  fromDate: Date;
  toDate: Date;
  width: number | string;
  height: number | string;
  selectedPmIds?: string[];
  onBlockHover?: (block: CompressedBlock | null) => void;
  onBlockClick?: (block: CompressedBlock) => void;
  onMonthClick?: (month: number, year: number) => void;
}

// =============================================================================
// Component
// =============================================================================

/**
 * Tactical Wide View
 *
 * Renders compressed PM blocks at monthly granularity using deck.gl.
 * Optimized for 60fps rendering when viewing a full year of data.
 */
export function TacticalWideLayer({
  data,
  fromDate,
  toDate,
  width,
  height,
  selectedPmIds = [],
  onBlockHover,
  onBlockClick,
  onMonthClick,
}: TacticalWideLayerProps) {
  if (!data || data.trains.length === 0) {
    return (
      <div
        style={{
          width,
          height,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'var(--pt-text-muted)',
        }}
      >
        No tactical-wide data available
      </div>
    );
  }

  const months = generateMonths(fromDate, toDate);
  const blocks = transformToCompressedBlocks(data, fromDate);
  const trainCount = data.trains.length;

  const canvasWidth = LABEL_WIDTH + months.length * MONTH_WIDTH + 40;
  const canvasHeight = HEADER_HEIGHT + trainCount * ROW_HEIGHT + 40;

  // Generate month labels
  const monthLabels: MonthLabel[] = months.map((m, index) => ({
    text: `${MONTH_NAMES[m.month]} ${m.year}`,
    month: m.month,
    year: m.year,
    position: [
      LABEL_WIDTH + index * MONTH_WIDTH + MONTH_WIDTH / 2,
      HEADER_HEIGHT / 2,
    ] as [number, number],
  }));

  // Generate train labels
  const trainLabels: TrainLabel[] = data.trains.map((train, index) => ({
    text: train.trainNumber,
    trainId: train.trainId,
    fleetCode: train.fleetCode,
    position: [
      LABEL_WIDTH / 2,
      HEADER_HEIGHT + index * ROW_HEIGHT + ROW_HEIGHT / 2,
    ] as [number, number],
  }));

  // Create grid lines for months
  const gridLines: Array<{ polygon: [number, number][] }> = months.map((_, index) => {
    const x = LABEL_WIDTH + index * MONTH_WIDTH;
    return {
      polygon: [
        [x, HEADER_HEIGHT],
        [x + 1, HEADER_HEIGHT],
        [x + 1, HEADER_HEIGHT + trainCount * ROW_HEIGHT],
        [x, HEADER_HEIGHT + trainCount * ROW_HEIGHT],
      ] as [number, number][],
    };
  });

  // Create row lines for trains
  const rowLines: Array<{ polygon: [number, number][] }> = data.trains.map((_, index) => {
    const y = HEADER_HEIGHT + index * ROW_HEIGHT;
    return {
      polygon: [
        [LABEL_WIDTH, y],
        [LABEL_WIDTH + months.length * MONTH_WIDTH, y],
        [LABEL_WIDTH + months.length * MONTH_WIDTH, y + 1],
        [LABEL_WIDTH, y + 1],
      ] as [number, number][],
    };
  });

  const layers = [
    // Grid lines - months
    new PolygonLayer<{ polygon: [number, number][] }>({
      id: 'month-grid',
      data: gridLines,
      pickable: false,
      filled: true,
      getPolygon: (d) => d.polygon,
      getFillColor: [226, 232, 240, 255], // Slate-200
    }),

    // Grid lines - rows
    new PolygonLayer<{ polygon: [number, number][] }>({
      id: 'row-grid',
      data: rowLines,
      pickable: false,
      filled: true,
      getPolygon: (d) => d.polygon,
      getFillColor: [241, 245, 249, 255], // Slate-100
    }),

    // PM Blocks
    new PolygonLayer<CompressedBlock>({
      id: 'pm-blocks',
      data: blocks,
      pickable: true,
      filled: true,
      stroked: true,
      extruded: false,
      getPolygon: (d) => d.polygon,
      getFillColor: (d) => {
        const color = getStatusColor(d.status);
        // Highlight selected blocks
        if (selectedPmIds.includes(d.pmId)) {
          return [color[0], color[1], color[2], 255] as [number, number, number, number];
        }
        return [color[0], color[1], color[2], 200] as [number, number, number, number];
      },
      getLineColor: (d) => {
        if (selectedPmIds.includes(d.pmId)) {
          return [30, 58, 138, 255]; // Blue-900 for selected
        }
        if (d.isLocked) {
          return [245, 158, 11, 255]; // Amber-500 for locked
        }
        return [100, 116, 139, 255]; // Slate-500
      },
      getLineWidth: (d) => (selectedPmIds.includes(d.pmId) ? 2 : 1),
      lineWidthMinPixels: 1,
      onHover: (info) => {
        if (onBlockHover) {
          onBlockHover(info.object ?? null);
        }
      },
      onClick: (info) => {
        if (info.object && onBlockClick) {
          onBlockClick(info.object);
        }
      },
      updateTriggers: {
        getFillColor: [selectedPmIds, data],
        getLineColor: [selectedPmIds],
        getLineWidth: [selectedPmIds],
      },
    }),

    // PM Code Labels (on blocks)
    new TextLayer<CompressedBlock>({
      id: 'pm-labels',
      data: blocks.filter((b) => b.durationWeeks >= 2), // Only show labels on larger blocks
      pickable: false,
      getPosition: (d) => {
        const x = (d.polygon[0][0] + d.polygon[1][0]) / 2;
        const y = (d.polygon[0][1] + d.polygon[2][1]) / 2;
        return [x, y, 0] as [number, number, number];
      },
      getText: (d) => d.pmCode,
      getSize: 10,
      getAngle: 0,
      getTextAnchor: 'middle',
      getAlignmentBaseline: 'center',
      getColor: [255, 255, 255, 255],
      fontFamily: 'Inter, system-ui, sans-serif',
      fontWeight: 600,
    }),

    // Train labels
    new TextLayer<TrainLabel>({
      id: 'train-labels',
      data: trainLabels,
      pickable: false,
      getPosition: (d) => [...d.position, 0] as [number, number, number],
      getText: (d) => d.text,
      getSize: 12,
      getAngle: 0,
      getTextAnchor: 'middle',
      getAlignmentBaseline: 'center',
      getColor: (d) => FLEET_COLORS[d.fleetCode] || FLEET_COLORS.DEFAULT,
      fontFamily: 'Inter, system-ui, sans-serif',
      fontWeight: 600,
    }),

    // Month labels
    new TextLayer<MonthLabel>({
      id: 'month-labels',
      data: monthLabels,
      pickable: true,
      getPosition: (d) => [...d.position, 0] as [number, number, number],
      getText: (d) => d.text,
      getSize: 12,
      getAngle: 0,
      getTextAnchor: 'middle',
      getAlignmentBaseline: 'center',
      getColor: [30, 41, 59, 255], // Slate-800
      fontFamily: 'Inter, system-ui, sans-serif',
      fontWeight: 700,
      onClick: (info) => {
        if (info.object && onMonthClick) {
          onMonthClick(info.object.month, info.object.year);
        }
      },
    }),
  ];

  const initialViewState = {
    target: [canvasWidth / 2, canvasHeight / 2, 0] as [number, number, number],
    zoom: 0,
    minZoom: -2,
    maxZoom: 4,
  };

  return (
    <DeckGL
      width={width}
      height={height}
      views={new OrthographicView({ id: 'main' })}
      initialViewState={initialViewState}
      controller={{
        scrollZoom: true,
        dragPan: true,
        dragRotate: false,
        doubleClickZoom: true,
        touchZoom: true,
        touchRotate: false,
        keyboard: true,
      }}
      layers={layers}
      getCursor={({ isHovering }) => (isHovering ? 'pointer' : 'grab')}
      style={{ position: 'absolute', top: '0', left: '0' }}
    />
  );
}

// =============================================================================
// Tooltip Component
// =============================================================================

export interface TacticalWideTooltipProps {
  block: CompressedBlock | null;
  x: number;
  y: number;
}

/**
 * Tooltip for PM block hover
 */
export function TacticalWideTooltip({ block, x, y }: TacticalWideTooltipProps) {
  if (!block) return null;

  return (
    <div
      style={{
        position: 'absolute',
        left: x + 10,
        top: y + 10,
        backgroundColor: 'white',
        border: '1px solid #e2e8f0',
        borderRadius: '6px',
        padding: '8px 12px',
        boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
        pointerEvents: 'none',
        zIndex: 100,
        fontSize: '12px',
        lineHeight: 1.5,
      }}
    >
      <div style={{ fontWeight: 600, marginBottom: '4px' }}>
        {block.pmCode} - Train {block.trainNumber}
      </div>
      <div style={{ color: '#64748b' }}>
        <div>Target Date: <strong>{block.targetDate}</strong></div>
        <div>Status: <strong>{block.status}</strong></div>
        <div>Duration: <strong>~{block.durationWeeks} week(s)</strong></div>
        {block.isLocked && (
          <div style={{ color: '#d97706' }}>🔒 Locked</div>
        )}
      </div>
    </div>
  );
}

export default TacticalWideLayer;

