   433→interface PmCardProps {
   434→  pm: OperationalPmBlock;
   435→  x: number;
   436→  y: number;
   437→  width: number;
   438→  isSelected: boolean;
   439→  onHover?: (pm: OperationalPmBlock | null) => void;
